  @state logPerRow = deps.logPerRow   or function () return 1 end  @ 35
  @state moveHook = deps.moveHook    or function () end  @ 36
  @state groupBridge = deps.groupBridge  @ 37
  @state cursorRow, cursorCol, cursorStop = 0, 1, 1  @ 39
  @state hBlockScope, vBlockScope = 0, 0  @ 40
